"""QIF file parser - converts Quicken QIF format to Python data structures."""

import re
from datetime import datetime


def parse_date(qif_date: str) -> str:
    """
    Convert QIF date format to ISO format.

    QIF format: M/DD'YY or M/ D'YY (with spaces)
    Examples: 8/20'24 -> 2024-08-20, 1/ 1'25 -> 2025-01-01

    Returns: YYYY-MM-DD string
    """
    # Remove any extra spaces
    qif_date = qif_date.strip().replace(" ", "")

    # Parse M/DD'YY format
    match = re.match(r"(\d{1,2})/(\d{1,2})'(\d{2})", qif_date)
    if match:
        month, day, year = match.groups()
        # Assume 2000s for years < 50, 1900s for >= 50
        year_int = int(year)
        full_year = 2000 + year_int if year_int < 50 else 1900 + year_int
        return f"{full_year}-{int(month):02d}-{int(day):02d}"

    raise ValueError(f"Cannot parse date: {qif_date}")


def parse_amount(qif_amount: str) -> float:
    """
    Convert QIF amount string to float.

    Handles commas and negative values.
    Examples: 1,589.27 -> 1589.27, -13.95 -> -13.95
    """
    if not qif_amount:
        return 0.0
    # Remove commas and convert
    return float(qif_amount.replace(",", ""))


def parse_cleared_status(status: str) -> str | None:
    """Convert QIF cleared status to database value."""
    if not status:
        return None
    status = status.strip().upper()
    if status == "X":
        return "reconciled"
    elif status in ("*", "C"):
        return "cleared"
    return None


def parse_qif_file(file_path: str) -> dict:
    """
    Parse a QIF file and return structured data.

    Returns:
        dict with keys: categories, accounts, securities, transactions, investment_transactions
    """
    with open(file_path, "r", encoding="utf-8", errors="replace") as f:
        content = f.read()

    result = {
        "categories": [],
        "accounts": [],
        "securities": [],
        "transactions": [],
        "investment_transactions": [],
    }

    # Split into records by ^
    lines = content.split("\n")

    current_section = None
    current_account = None
    current_record = {}

    for line in lines:
        line = line.rstrip()

        if not line:
            continue

        # Section headers
        if line.startswith("!Type:Cat"):
            current_section = "category"
            current_record = {}
            continue
        elif line.startswith("!Type:Security"):
            current_section = "security"
            current_record = {}
            continue
        elif line.startswith("!Type:Bank") or line.startswith("!Type:CCard"):
            current_section = "transaction"
            current_record = {}
            continue
        elif line.startswith("!Type:Invst"):
            current_section = "investment"
            current_record = {}
            continue
        elif line.startswith("!Account"):
            current_section = "account"
            current_record = {}
            continue
        elif line.startswith("!"):
            # Other directives (Option, Clear, etc.) - ignore
            continue

        # Record delimiter
        if line == "^":
            if current_section == "category" and current_record.get("name"):
                result["categories"].append(current_record)
            elif current_section == "account" and current_record.get("name"):
                result["accounts"].append(current_record)
                current_account = current_record.get("name")
            elif current_section == "security" and current_record.get("name"):
                result["securities"].append(current_record)
            elif current_section == "transaction" and current_record.get("date"):
                current_record["account"] = current_account
                result["transactions"].append(current_record)
            elif current_section == "investment" and current_record.get("date"):
                current_record["account"] = current_account
                result["investment_transactions"].append(current_record)
            current_record = {}
            continue

        # Parse field codes
        if len(line) < 1:
            continue

        field_code = line[0]
        field_value = line[1:] if len(line) > 1 else ""

        # Category fields
        if current_section == "category":
            if field_code == "N":
                current_record["name"] = field_value
            elif field_code == "D":
                current_record["description"] = field_value
            elif field_code == "I":
                current_record["type"] = "income"
            elif field_code == "E":
                current_record["type"] = "expense"

        # Account fields
        elif current_section == "account":
            if field_code == "N":
                current_record["name"] = field_value
            elif field_code == "T":
                current_record["type"] = field_value

        # Security fields
        elif current_section == "security":
            if field_code == "N":
                current_record["name"] = field_value
            elif field_code == "S":
                current_record["symbol"] = field_value
            elif field_code == "T":
                current_record["security_type"] = field_value

        # Transaction fields (Bank/CCard)
        elif current_section == "transaction":
            if field_code == "D":
                try:
                    current_record["date"] = parse_date(field_value)
                except ValueError:
                    current_record["date"] = None
            elif field_code == "U":
                current_record["amount"] = parse_amount(field_value)
            elif field_code == "T" and "amount" not in current_record:
                # T is legacy duplicate of U, only use if U not present
                current_record["amount"] = parse_amount(field_value)
            elif field_code == "P":
                current_record["payee"] = field_value
            elif field_code == "L":
                current_record["category"] = field_value
            elif field_code == "C":
                current_record["cleared"] = parse_cleared_status(field_value)
            elif field_code == "M":
                current_record["memo"] = field_value

        # Investment transaction fields
        elif current_section == "investment":
            if field_code == "D":
                try:
                    current_record["date"] = parse_date(field_value)
                except ValueError:
                    current_record["date"] = None
            elif field_code == "N":
                current_record["action"] = field_value
            elif field_code == "Y":
                current_record["security"] = field_value
            elif field_code == "I":
                current_record["price"] = parse_amount(field_value)
            elif field_code == "Q":
                current_record["quantity"] = parse_amount(field_value)
            elif field_code == "O":
                current_record["commission"] = parse_amount(field_value)
            elif field_code == "U":
                current_record["amount"] = parse_amount(field_value)
            elif field_code == "T" and "amount" not in current_record:
                current_record["amount"] = parse_amount(field_value)
            elif field_code == "L":
                current_record["transfer_account"] = field_value
            elif field_code == "C":
                current_record["cleared"] = parse_cleared_status(field_value)
            elif field_code == "M":
                current_record["memo"] = field_value

    return result


if __name__ == "__main__":
    import sys
    import json

    if len(sys.argv) < 2:
        print("Usage: python qif_parser.py <qif_file>")
        sys.exit(1)

    data = parse_qif_file(sys.argv[1])
    print(f"Categories: {len(data['categories'])}")
    print(f"Accounts: {len(data['accounts'])}")
    print(f"Securities: {len(data['securities'])}")
    print(f"Transactions: {len(data['transactions'])}")
    print(f"Investment Transactions: {len(data['investment_transactions'])}")
